// Extract the vendored @dicebear/notionists-neutral component library into plain,
// categorized SVG fragment files: priv/avatar/<group>/<variant>.svg
// Run once (or after a vendor upgrade):  bun vendor/extract.mjs
// License: Notionists by Zoish, CC0 1.0 (see vendor/notionists-neutral/LICENSE).
import { mkdirSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

import { brows } from "./notionists-neutral/lib/components/brows.js";
import { eyes } from "./notionists-neutral/lib/components/eyes.js";
import { glasses } from "./notionists-neutral/lib/components/glasses.js";
import { lips } from "./notionists-neutral/lib/components/lips.js";
import { nose } from "./notionists-neutral/lib/components/nose.js";

const root = join(dirname(fileURLToPath(import.meta.url)), "..", "priv", "avatar");

// group -> [transform from the style's create(), variants]
const groups = {
  lips: ["translate(136 328)", lips],
  nose: ["translate(246 125)", nose],
  eyes: ["translate(-45 137)", eyes],
  glasses: ["translate(-45 137)", glasses],
  brows: ["translate(119 114)", brows],
};

let manifest = "# group transform variants — generated by vendor/extract.mjs\n";

for (const [group, [transform, variants]] of Object.entries(groups)) {
  const dir = join(root, group);
  mkdirSync(dir, { recursive: true });
  const names = Object.keys(variants).sort();

  for (const name of names) {
    const svg = variants[name]({}, {});
    if (svg.includes("undefined")) throw new Error(`${group}/${name} needs inputs`);
    writeFileSync(join(dir, `${name}.svg`), svg);
  }

  manifest += `${group} ${transform} ${names.join(",")}\n`;
  console.log(`${group}: ${names.length} variants`);
}

writeFileSync(join(root, "manifest.txt"), manifest);
console.log("done ->", root);
